module edge_detect (
    input clk,
    input rst_n,
    input a,
    output reg rise,
    output reg down
);

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin

        rise <= 1'b0;
        down <= 1'b0;
    end else begin

        if (a && !prev_a) begin

            rise <= 1'b1;
            down <= 1'b0;
        end else if (!a && prev_a) begin

            rise <= 1'b0;
            down <= 1'b1;
        end else begin

            rise <= 1'b0;
            down <= 1'b0;
        end
    end
end

reg prev_a;

always @(posedge clk) begin

    prev_a <= a;
end
endmodule
